# Step 1: Clean up partial migration
psql "$DATABASE_URL" <<'EOF'
-- Drop tables in reverse dependency order
DROP TABLE IF EXISTS public.type_order_default_work_orders CASCADE;
DROP TABLE IF EXISTS public.type_order_compositions CASCADE;
DROP TABLE IF EXISTS public.bom_action_requests CASCADE;
DROP TABLE IF EXISTS public.type_orders CASCADE;
DROP TABLE IF EXISTS public.trade_outcome_assignments CASCADE;
DROP TABLE IF EXISTS public.organization_trades CASCADE;
DROP TABLE IF EXISTS public.project_outcomes CASCADE;
DROP TABLE IF EXISTS public.trades CASCADE;

-- Drop triggers that may have been created
DROP TRIGGER IF EXISTS trg_sync_trade_name_templates ON public.work_order_templates;
DROP TRIGGER IF EXISTS trg_sync_trade_name_work_orders ON public.work_orders;
DROP TRIGGER IF EXISTS trg_sync_trade_name_code_sops ON public.sops;
DROP FUNCTION IF EXISTS public.sync_trade_name() CASCADE;
DROP FUNCTION IF EXISTS public.sync_trade_name_and_code() CASCADE;

-- Revert scope rename constraints back to original state
-- The migration already changed valid_app_scope -> valid_system_scope, revert
ALTER TABLE public.work_order_templates DROP CONSTRAINT IF EXISTS valid_system_scope;
ALTER TABLE public.work_order_templates DROP CONSTRAINT IF EXISTS work_order_templates_scope_check;
-- Re-add original constraints
ALTER TABLE public.work_order_templates ADD CONSTRAINT work_order_templates_scope_check
  CHECK (scope IN ('system', 'company', 'project'));
ALTER TABLE public.work_order_templates ADD CONSTRAINT valid_system_scope
  CHECK ((scope = 'system' AND organization_id IS NULL AND project_id IS NULL) OR scope <> 'system');

-- template_libraries - already has valid_system_library, that's fine
ALTER TABLE public.template_libraries DROP CONSTRAINT IF EXISTS template_libraries_scope_check;
ALTER TABLE public.template_libraries ADD CONSTRAINT template_libraries_scope_check
  CHECK (scope IN ('system', 'company'));

SELECT 'Cleanup complete' as status;
EOF

